code.C:
#include <stdio.h>
int main() {
    int n, k;
    scanf("%d %d", &n, &k);
    while (k--) {
        if (n > 10) {
            n -= 10;
        } else {
            n = 0;
        }
    }
    printf("%d\n", n);
    return 0;
}

