const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
readline.on('line', line => {
    const [n, k] = line.split(' ').map(Number);
    let result = n;
    for (let i = 0; i < k; i++) {
        if (result > 10) {
            result -= 10;
        } else {
            result = 0;
        }
    }
    console.log(result);
});
